import os

base = "poll_portal/templates/poll_portal"
os.makedirs(base, exist_ok=True)

base_html = "{% load static %}\n<!DOCTYPE html>\n<html lang=\"en\">\n<head>\n  <meta charset=\"UTF-8\">\n  <meta name=\"viewport\" content=\"width=device-width, initial-scale=1.0\">\n  <title>{% block title %}VoteSphere{% endblock %} | VoteSphere</title>\n  <link href=\"https://cdn.jsdelivr.net/npm/bootstrap@5.3.3/dist/css/bootstrap.min.css\" rel=\"stylesheet\">\n  <link href=\"https://cdn.jsdelivr.net/npm/bootstrap-icons@1.11.3/font/bootstrap-icons.min.css\" rel=\"stylesheet\">\n  <style>\n    *,*::before,*::after{box-sizing:border-box;}\n    body{background:#f0f4f8;font-family:'Segoe UI',system-ui,sans-serif;color:#1a1a2e;min-height:100vh;display:flex;flex-direction:column;}\n\n    /* \u2500\u2500 NAVBAR \u2500\u2500 */\n    .navbar{background:linear-gradient(135deg,#1d4ed8 0%,#2563eb 60%,#3b82f6 100%)!important;box-shadow:0 4px 24px rgba(37,99,235,.4);padding:.75rem 0;}\n    .navbar-brand{font-weight:800;font-size:1.3rem;color:#fff!important;letter-spacing:-.3px;}\n    .navbar-brand i{color:#fde68a;}\n    .navbar .nav-link{color:rgba(255,255,255,.88)!important;font-weight:500;font-size:.88rem;padding:.45rem .9rem!important;border-radius:8px;transition:all .18s;}\n    .navbar .nav-link:hover{color:#fff!important;background:rgba(255,255,255,.16);}\n    .badge-admin{background:linear-gradient(135deg,#f59e0b,#d97706);color:#fff;font-size:.7rem;padding:3px 9px;border-radius:20px;font-weight:700;margin-left:4px;}\n    .user-avatar{width:32px;height:32px;border-radius:50%;background:rgba(255,255,255,.25);border:2px solid rgba(255,255,255,.4);display:inline-flex;align-items:center;justify-content:center;font-weight:700;font-size:.85rem;color:#fff;}\n\n    /* \u2500\u2500 LAYOUT \u2500\u2500 */\n    .main-content{flex:1;}\n\n    /* \u2500\u2500 CARDS \u2500\u2500 */\n    .card{border:none;border-radius:18px;box-shadow:0 2px 12px rgba(0,0,0,.06);transition:transform .2s,box-shadow .2s;}\n    .card:hover{box-shadow:0 6px 28px rgba(0,0,0,.1);}\n    .card-header{border-radius:18px 18px 0 0!important;border-bottom:none;padding:1.2rem 1.5rem;}\n    .card-header-indigo{background:linear-gradient(135deg,#2563eb,#1d4ed8);color:#fff;}\n    .card-header-dark{background:linear-gradient(135deg,#0f172a,#1e3a5f);color:#fff;}\n    .card-footer{background:#f8fafd;border-top:1px solid #eef2f7;border-radius:0 0 18px 18px!important;padding:.9rem 1.5rem;}\n\n    /* \u2500\u2500 BUTTONS \u2500\u2500 */\n    .btn{font-weight:600;font-size:.85rem;border-radius:10px;transition:all .18s;letter-spacing:.01em;}\n    .btn-primary{background:linear-gradient(135deg,#2563eb,#1d4ed8);border:none;box-shadow:0 4px 14px rgba(37,99,235,.35);}\n    .btn-primary:hover,.btn-primary:focus{background:linear-gradient(135deg,#1d4ed8,#1e40af);box-shadow:0 6px 20px rgba(37,99,235,.45);transform:translateY(-1px);}\n    .btn-success{background:linear-gradient(135deg,#10b981,#059669);border:none;box-shadow:0 4px 12px rgba(16,185,129,.25);}\n    .btn-success:hover{background:linear-gradient(135deg,#059669,#047857);transform:translateY(-1px);}\n    .btn-danger{background:linear-gradient(135deg,#ef4444,#dc2626);border:none;box-shadow:0 4px 12px rgba(239,68,68,.25);}\n    .btn-danger:hover{background:linear-gradient(135deg,#dc2626,#b91c1c);transform:translateY(-1px);}\n    .btn-warning{background:linear-gradient(135deg,#f59e0b,#d97706);border:none;color:#fff;}\n    .btn-outline-primary{border:2px solid #2563eb;color:#2563eb;background:transparent;}\n    .btn-outline-primary:hover{background:#2563eb;color:#fff;border-color:#2563eb;}\n    .btn-outline-secondary{border:1.5px solid #cbd5e1;color:#64748b;}\n    .btn-outline-secondary:hover{background:#f1f5f9;color:#334155;border-color:#94a3b8;}\n    .btn-outline-success{border:1.5px solid #10b981;color:#059669;}\n    .btn-outline-success:hover{background:#d1fae5;}\n    .btn-outline-danger{border:1.5px solid #ef4444;color:#dc2626;}\n    .btn-outline-danger:hover{background:#fee2e2;}\n    .btn-outline-warning{border:1.5px solid #f59e0b;color:#d97706;}\n    .btn-outline-warning:hover{background:#fef3c7;}\n\n    /* \u2500\u2500 FORMS \u2500\u2500 */\n    .form-control,.form-select{border-radius:10px;border:1.5px solid #dde3ee;padding:.6rem 1rem;font-size:.9rem;transition:border-color .2s,box-shadow .2s;background:#fff;}\n    .form-control:focus,.form-select:focus{border-color:#2563eb;box-shadow:0 0 0 3px rgba(37,99,235,.14);outline:none;}\n    .input-group-text{border-radius:10px 0 0 10px;border:1.5px solid #dde3ee;border-right:none;background:#eff6ff;color:#2563eb;}\n    .input-group .form-control{border-radius:0 10px 10px 0;}\n    .form-label{font-weight:600;font-size:.83rem;color:#374151;margin-bottom:.35rem;text-transform:uppercase;letter-spacing:.04em;}\n    .form-text{font-size:.76rem;color:#94a3b8;}\n\n    /* \u2500\u2500 ALERTS \u2500\u2500 */\n    .alert{border-radius:14px;border:none;font-size:.875rem;font-weight:500;display:flex;align-items:center;gap:.6rem;}\n    .alert-success{background:#d1fae5;color:#065f46;}\n    .alert-danger{background:#fee2e2;color:#991b1b;}\n    .alert-warning{background:#fef3c7;color:#92400e;}\n    .alert-info{background:#dbeafe;color:#1e40af;}\n\n    /* \u2500\u2500 HERO \u2500\u2500 */\n    .hero-section{background:linear-gradient(135deg,#1d4ed8 0%,#2563eb 55%,#3b82f6 100%);color:#fff;padding:3.5rem 0 3rem;margin-bottom:2.5rem;border-radius:0 0 40px 40px;position:relative;overflow:hidden;}\n    .hero-section::before{content:'';position:absolute;top:-80px;right:-80px;width:350px;height:350px;background:rgba(255,255,255,.05);border-radius:50%;}\n    .hero-section::after{content:'';position:absolute;bottom:-100px;left:-50px;width:250px;height:250px;background:rgba(255,255,255,.04);border-radius:50%;}\n\n    /* \u2500\u2500 POLL CARDS \u2500\u2500 */\n    .poll-card{transition:transform .22s,box-shadow .22s!important;}\n    .poll-card:hover{transform:translateY(-5px)!important;box-shadow:0 14px 40px rgba(37,99,235,.16)!important;}\n    .option-chip{display:flex;align-items:flex-start;gap:.6rem;padding:.55rem .75rem;background:#eff6ff;border-radius:10px;font-size:.85rem;color:#374151;font-weight:500;}\n    .option-dot{width:8px;height:8px;border-radius:50%;flex-shrink:0;margin-top:4px;}\n\n    /* \u2500\u2500 PROGRESS \u2500\u2500 */\n    .progress{border-radius:30px;height:26px;background:#dbeafe;overflow:hidden;}\n    .progress-bar{display:flex;align-items:center;justify-content:center;font-size:.74rem;font-weight:700;border-radius:30px;transition:width .7s cubic-bezier(.4,0,.2,1);}\n\n    /* \u2500\u2500 WINNER \u2500\u2500 */\n    .winner-badge{background:linear-gradient(135deg,#f59e0b,#d97706);color:#fff;border-radius:20px;padding:3px 10px;font-size:.7rem;font-weight:700;display:inline-flex;align-items:center;gap:3px;}\n\n    /* \u2500\u2500 VOTE OPTIONS \u2500\u2500 */\n    .vote-option{cursor:pointer;border:2px solid #e8ecf4;border-radius:14px;padding:1rem 1.2rem;transition:all .2s;background:#fff;display:flex;align-items:center;gap:.75rem;}\n    .vote-option:hover{border-color:#2563eb;background:#eff6ff;}\n    .vote-option input[type=radio]{accent-color:#2563eb;width:1.15em;height:1.15em;flex-shrink:0;}\n    .vote-option input[type=radio]:checked~*{color:#2563eb;}\n\n    /* \u2500\u2500 TABLE \u2500\u2500 */\n    .table{font-size:.875rem;}\n    .table th{font-weight:700;color:#64748b;text-transform:uppercase;font-size:.7rem;letter-spacing:.06em;border-bottom:2px solid #eef2f7;padding:.85rem 1rem;}\n    .table td{vertical-align:middle;border-color:#f4f7fb;padding:.8rem 1rem;}\n    .table-hover tbody tr:hover{background:#f0f7ff;}\n\n    /* \u2500\u2500 STAT CARDS \u2500\u2500 */\n    .stat-card{border-radius:18px;padding:1.6rem 1.4rem;background:#fff;box-shadow:0 2px 14px rgba(0,0,0,.06);text-align:center;position:relative;overflow:hidden;}\n    .stat-number{font-size:2.6rem;font-weight:800;line-height:1;margin-bottom:.25rem;}\n    .stat-label{font-size:.75rem;font-weight:700;text-transform:uppercase;letter-spacing:.06em;color:#94a3b8;}\n    .stat-icon{position:absolute;bottom:-10px;right:-10px;font-size:4.5rem;opacity:.06;}\n\n    /* \u2500\u2500 MISC \u2500\u2500 */\n    .divider{height:1px;background:linear-gradient(to right,transparent,#e2e8f0,transparent);margin:1.2rem 0;}\n    .text-muted{color:#94a3b8!important;}\n    footer{background:linear-gradient(135deg,#0f172a,#1e3a5f);color:#93c5fd;padding:1.8rem 0;margin-top:auto;}\n    .section-badge{display:inline-flex;align-items:center;gap:6px;background:rgba(255,255,255,.15);border:1px solid rgba(255,255,255,.2);border-radius:30px;padding:.3rem 1rem;font-size:.8rem;font-weight:600;}\n  </style>\n</head>\n<body>\n\n<nav class=\"navbar navbar-expand-lg\">\n  <div class=\"container\">\n    <a class=\"navbar-brand d-flex align-items-center gap-2\" href=\"{% url 'home' %}\">\n      <span style=\"width:34px;height:34px;background:rgba(255,255,255,.2);border-radius:10px;display:inline-flex;align-items:center;justify-content:center;flex-shrink:0;\">\n        <i class=\"bi bi-bar-chart-line-fill\" style=\"color:#fde68a;font-size:1rem;\"></i>\n      </span>\n      VoteSphere\n    </a>\n    <button class=\"navbar-toggler border-0\" type=\"button\" data-bs-toggle=\"collapse\" data-bs-target=\"#navMenu\">\n      <span class=\"navbar-toggler-icon\" style=\"filter:invert(1)\"></span>\n    </button>\n    <div class=\"collapse navbar-collapse\" id=\"navMenu\">\n      <ul class=\"navbar-nav me-auto mb-2 mb-lg-0 gap-1 ms-3\">\n        <li class=\"nav-item\"><a class=\"nav-link\" href=\"{% url 'home' %}\"><i class=\"bi bi-house-door me-1\"></i>Home</a></li>\n        {% if user.is_authenticated and user.is_staff %}\n        <li class=\"nav-item\"><a class=\"nav-link\" href=\"{% url 'create' %}\"><i class=\"bi bi-plus-circle me-1\"></i>New Poll</a></li>\n        <li class=\"nav-item\"><a class=\"nav-link\" href=\"{% url 'admin_dashboard' %}\"><i class=\"bi bi-speedometer2 me-1\"></i>Dashboard</a></li>\n        <li class=\"nav-item\"><a class=\"nav-link\" href=\"{% url 'admin:index' %}\"><i class=\"bi bi-shield-lock me-1\"></i>Admin</a></li>\n        {% endif %}\n      </ul>\n      <ul class=\"navbar-nav ms-auto align-items-center gap-2\">\n        {% if user.is_authenticated %}\n        <li class=\"nav-item dropdown\">\n          <a class=\"nav-link dropdown-toggle d-flex align-items-center gap-2 py-1\" href=\"#\" data-bs-toggle=\"dropdown\">\n            <span class=\"user-avatar\">{{ user.username|first|upper }}</span>\n            <span class=\"fw-600\" style=\"font-weight:600;\">{{ user.username }}</span>\n            {% if user.is_staff %}<span class=\"badge-admin\">Admin</span>{% endif %}\n          </a>\n          <ul class=\"dropdown-menu dropdown-menu-end border-0 shadow-lg\" style=\"border-radius:14px;min-width:170px;padding:.4rem;\">\n            <li>\n              <span class=\"dropdown-item-text px-3 pb-1\" style=\"font-size:.78rem;color:#94a3b8;\">Signed in as</span>\n            </li>\n            <li>\n              <span class=\"dropdown-item-text px-3 pb-2\" style=\"font-weight:700;color:#0f172a;font-size:.88rem;\">{{ user.username }}</span>\n            </li>\n            <li><hr class=\"dropdown-divider my-1\"></li>\n            <li>\n              <a class=\"dropdown-item d-flex align-items-center gap-2 text-danger rounded-3\" href=\"{% url 'logout' %}\" style=\"font-size:.875rem;padding:.55rem .85rem;\">\n                <i class=\"bi bi-box-arrow-right\"></i>Sign Out\n              </a>\n            </li>\n          </ul>\n        </li>\n        {% else %}\n        <li class=\"nav-item\">\n          <a class=\"nav-link\" href=\"{% url 'login' %}\">\n            <i class=\"bi bi-box-arrow-in-right me-1\"></i>Login\n          </a>\n        </li>\n        <li class=\"nav-item\">\n          <a href=\"{% url 'register' %}\" class=\"btn btn-sm\" style=\"background:rgba(255,255,255,.18);color:#fff;border:1.5px solid rgba(255,255,255,.4);border-radius:10px;font-weight:700;padding:.38rem 1rem;\">\n            <i class=\"bi bi-person-plus me-1\"></i>Register\n          </a>\n        </li>\n        {% endif %}\n      </ul>\n    </div>\n  </div>\n</nav>\n\n<div class=\"main-content\">\n  <div class=\"container mt-4\">\n    {% for message in messages %}\n    <div class=\"alert alert-{{ message.tags }} alert-dismissible fade show\" role=\"alert\">\n      {% if message.tags == 'success' %}<i class=\"bi bi-check-circle-fill fs-5\"></i>\n      {% elif message.tags == 'danger' %}<i class=\"bi bi-x-circle-fill fs-5\"></i>\n      {% elif message.tags == 'warning' %}<i class=\"bi bi-exclamation-triangle-fill fs-5\"></i>\n      {% else %}<i class=\"bi bi-info-circle-fill fs-5\"></i>{% endif %}\n      <span>{{ message }}</span>\n      <button type=\"button\" class=\"btn-close ms-auto\" data-bs-dismiss=\"alert\"></button>\n    </div>\n    {% endfor %}\n\n    {% block main %}{% endblock %}\n  </div>\n</div>\n\n<footer>\n  <div class=\"container\">\n    <div class=\"row align-items-center\">\n      <div class=\"col text-center\">\n        <div class=\"d-inline-flex align-items-center gap-2 mb-1\">\n          <i class=\"bi bi-bar-chart-line-fill\" style=\"color:#fde68a;font-size:1.1rem;\"></i>\n          <span style=\"font-weight:800;font-size:1rem;color:#dbeafe;\">VoteSphere</span>\n        </div>\n          <div style=\"font-size:.8rem;color:#60a5fa;\">Secure, Simple, Fair Elections</div>\n      </div>\n    </div>\n  </div>\n</footer>\n\n<script src=\"https://cdn.jsdelivr.net/npm/bootstrap@5.3.3/dist/js/bootstrap.bundle.min.js\"></script>\n</body>\n</html>\n"
with open(os.path.join(base, "base.html"), "w", encoding="utf-8") as fh: fh.write(base_html)

home_html = "{% extends \"poll_portal/base.html\" %}\n{% block title %}Home{% endblock %}\n{% block main %}\n\n<div class=\"hero-section text-center position-relative\">\n  <div class=\"container position-relative\" style=\"z-index:1;\">\n    {% if not user.is_authenticated %}\n    <div class=\"section-badge mb-3\">\n      <i class=\"bi bi-lightning-charge-fill\" style=\"color:#fde68a;\"></i> Live Polling Platform\n    </div>\n    {% endif %}\n    <h1 class=\"fw-bold mb-2\" style=\"font-size:2.4rem;font-weight:800;letter-spacing:-.5px;\">\n      {% if user.is_authenticated %}Welcome back, {{ user.username }}!{% else %}Active Polls{% endif %}\n    </h1>\n    <p class=\"lead mb-0\" style=\"opacity:.85;\">Cast your vote securely \u2014 every voice matters</p>\n    {% if not user.is_authenticated %}\n    <div class=\"d-flex gap-3 justify-content-center mt-4\">\n      <a href=\"{% url 'login' %}\" class=\"btn px-5 py-2\" style=\"background:#fff;color:#2563eb;border-radius:12px;font-weight:700;font-size:.95rem;\">\n        <i class=\"bi bi-box-arrow-in-right me-2\"></i>Login\n      </a>\n      <a href=\"{% url 'register' %}\" class=\"btn px-5 py-2\" style=\"background:rgba(255,255,255,.18);color:#fff;border:2px solid rgba(255,255,255,.4);border-radius:12px;font-weight:600;\">\n        <i class=\"bi bi-person-plus me-2\"></i>Register\n      </a>\n    </div>\n    {% endif %}\n  </div>\n</div>\n\n{% if polls %}\n<div class=\"d-flex justify-content-between align-items-center mb-3\">\n  <div style=\"font-weight:700;color:#374151;font-size:.9rem;\">\n    <i class=\"bi bi-collection me-1\" style=\"color:#2563eb;\"></i>{{ polls|length }} Active Poll{{ polls|length|pluralize }}\n  </div>\n</div>\n<div class=\"row g-4\">\n  {% for poll in polls %}\n  <div class=\"col-md-6 col-lg-4\">\n    <div class=\"card poll-card h-100\" style=\"border-radius:18px;\">\n      <div class=\"card-header card-header-indigo d-flex justify-content-between align-items-start\" style=\"border-radius:18px 18px 0 0!important;\">\n        <div style=\"flex:1;\">\n          <div style=\"font-size:.68rem;opacity:.7;font-weight:700;text-transform:uppercase;letter-spacing:.1em;margin-bottom:.35rem;\">Poll #{{ poll.id }}</div>\n          <div class=\"fw-bold\" style=\"font-size:.95rem;line-height:1.4;font-weight:700;\">{{ poll.question }}</div>\n        </div>\n        <div class=\"ms-2 flex-shrink-0\">\n          {% if poll.id in voted_polls %}\n          <span style=\"background:rgba(255,255,255,.22);color:#fff;font-size:.7rem;font-weight:700;padding:.3em .8em;border-radius:8px;display:inline-block;\">\n            <i class=\"bi bi-check2 me-1\"></i>Voted\n          </span>\n          {% else %}\n          <span style=\"background:rgba(255,255,255,.14);color:rgba(255,255,255,.9);font-size:.7rem;font-weight:600;padding:.3em .8em;border-radius:8px;display:inline-block;\">Open</span>\n          {% endif %}\n        </div>\n      </div>\n      <div class=\"card-body d-flex flex-column p-4\">\n        <div class=\"d-flex flex-column gap-2 mb-4\">\n          <div class=\"option-chip\">\n            <span class=\"option-dot\" style=\"background:#2563eb;\"></span>\n            {{ poll.option_one }}\n          </div>\n          <div class=\"option-chip\">\n            <span class=\"option-dot\" style=\"background:#1d4ed8;\"></span>\n            {{ poll.option_two }}\n          </div>\n          <div class=\"option-chip\">\n            <span class=\"option-dot\" style=\"background:#3b82f6;\"></span>\n            {{ poll.option_three }}\n          </div>\n        </div>\n        <div class=\"mt-auto d-flex flex-wrap gap-2\">\n          {% if user.is_authenticated %}\n            {% if poll.id in voted_polls %}\n            <span class=\"btn btn-success btn-sm disabled px-3\">\n              <i class=\"bi bi-check2-circle me-1\"></i>Voted\n            </span>\n            {% else %}\n            <a href=\"{% url 'vote' poll.id %}\" class=\"btn btn-primary btn-sm px-3\">\n              <i class=\"bi bi-hand-index-thumb me-1\"></i>Vote\n            </a>\n            {% endif %}\n          {% else %}\n          <a href=\"{% url 'login' %}\" class=\"btn btn-primary btn-sm px-3\">\n            <i class=\"bi bi-hand-index-thumb me-1\"></i>Vote\n          </a>\n          {% endif %}\n          {% if poll.result_published or user.is_staff %}\n          <a href=\"{% url 'results' poll.id %}\" class=\"btn btn-outline-primary btn-sm px-3\">\n            <i class=\"bi bi-bar-chart me-1\"></i>Results\n          </a>\n          {% endif %}\n          {% if user.is_staff %}\n          <a href=\"{% url 'voters_list' poll.id %}\" class=\"btn btn-outline-secondary btn-sm px-3\">\n            <i class=\"bi bi-people me-1\"></i>Voters\n          </a>\n          {% endif %}\n        </div>\n      </div>\n      <div class=\"card-footer d-flex justify-content-between align-items-center\">\n        <span class=\"text-muted\" style=\"font-size:.78rem;font-weight:600;\">\n          <i class=\"bi bi-people-fill me-1\" style=\"color:#2563eb;\"></i>{{ poll.total }} vote{{ poll.total|pluralize }}\n        </span>\n        <span class=\"text-muted\" style=\"font-size:.78rem;\">\n          <i class=\"bi bi-calendar3 me-1\"></i>{{ poll.pub_date|date:\"M d, Y\" }}\n        </span>\n      </div>\n    </div>\n  </div>\n  {% endfor %}\n</div>\n{% else %}\n<div class=\"text-center py-5 my-3\">\n  <div style=\"width:80px;height:80px;background:linear-gradient(135deg,#eff6ff,#dbeafe);border-radius:50%;display:flex;align-items:center;justify-content:center;margin:0 auto 1.5rem;box-shadow:0 4px 20px rgba(37,99,235,.15);\">\n    <i class=\"bi bi-inbox\" style=\"font-size:2.2rem;color:#2563eb;\"></i>\n  </div>\n  <h4 style=\"font-weight:700;color:#0f172a;margin-bottom:.5rem;\">No Active Polls</h4>\n  <p class=\"text-muted mb-4\">Check back soon or ask an admin to create a new poll.</p>\n  {% if user.is_staff %}\n  <a href=\"{% url 'create' %}\" class=\"btn btn-primary px-5 py-2\">\n    <i class=\"bi bi-plus-circle me-2\"></i>Create First Poll\n  </a>\n  {% endif %}\n</div>\n{% endif %}\n\n{% endblock %}\n"
with open(os.path.join(base, "home.html"), "w", encoding="utf-8") as fh: fh.write(home_html)

login_html = "{% extends \"poll_portal/base.html\" %}\n{% block title %}Login{% endblock %}\n{% block main %}\n<div class=\"row justify-content-center\" style=\"margin-top:2rem;margin-bottom:3rem;\">\n  <div class=\"col-sm-9 col-md-6 col-lg-4\">\n\n    <div class=\"text-center mb-4\">\n      <div style=\"width:60px;height:60px;background:linear-gradient(135deg,#2563eb,#1d4ed8);border-radius:16px;display:flex;align-items:center;justify-content:center;margin:0 auto 1rem;box-shadow:0 8px 24px rgba(37,99,235,.35);\">\n        <i class=\"bi bi-bar-chart-line-fill\" style=\"font-size:1.6rem;color:#fff;\"></i>\n      </div>\n      <h2 style=\"font-weight:800;color:#0f172a;font-size:1.7rem;margin-bottom:.25rem;\">Welcome back</h2>\n      <p class=\"text-muted\" style=\"font-size:.88rem;\">Sign in to your VoteSphere account</p>\n    </div>\n\n    <div class=\"card shadow-lg\" style=\"border-radius:20px;\">\n      <div class=\"card-body p-4\">\n        <form method=\"POST\">\n          {% csrf_token %}\n          <input type=\"hidden\" name=\"next\" value=\"{{ next }}\">\n          <div class=\"mb-3\">\n            <label class=\"form-label\">Username</label>\n            <div class=\"input-group\">\n              <span class=\"input-group-text\"><i class=\"bi bi-person-fill\" style=\"color:#2563eb;\"></i></span>\n              <input type=\"text\" name=\"username\" class=\"form-control\" placeholder=\"Enter your username\" required autofocus>\n            </div>\n          </div>\n          <div class=\"mb-4\">\n            <label class=\"form-label\">Password</label>\n            <div class=\"input-group\">\n              <span class=\"input-group-text\"><i class=\"bi bi-lock-fill\" style=\"color:#2563eb;\"></i></span>\n              <input type=\"password\" name=\"password\" class=\"form-control\" placeholder=\"Enter your password\" required>\n            </div>\n          </div>\n          <button type=\"submit\" class=\"btn btn-primary w-100 py-2\" style=\"font-size:.95rem;\">\n            <i class=\"bi bi-box-arrow-in-right me-2\"></i>Sign In\n          </button>\n        </form>\n      </div>\n      <div class=\"card-footer text-center\" style=\"font-size:.875rem;\">\n        No account? <a href=\"{% url 'register' %}\" style=\"color:#2563eb;font-weight:700;text-decoration:none;\">Create one free</a>\n      </div>\n    </div>\n\n  </div>\n</div>\n{% endblock %}\n"
with open(os.path.join(base, "login.html"), "w", encoding="utf-8") as fh: fh.write(login_html)

register_html = "{% extends \"poll_portal/base.html\" %}\n{% block title %}Register{% endblock %}\n{% block main %}\n<div class=\"row justify-content-center\" style=\"margin-top:2rem;margin-bottom:3rem;\">\n  <div class=\"col-sm-10 col-md-7 col-lg-5\">\n\n    <div class=\"text-center mb-4\">\n      <div style=\"width:60px;height:60px;background:linear-gradient(135deg,#2563eb,#1d4ed8);border-radius:16px;display:flex;align-items:center;justify-content:center;margin:0 auto 1rem;box-shadow:0 8px 24px rgba(37,99,235,.3);\">\n        <i class=\"bi bi-person-plus-fill\" style=\"font-size:1.6rem;color:#fff;\"></i>\n      </div>\n      <h2 style=\"font-weight:800;color:#0f172a;font-size:1.7rem;margin-bottom:.25rem;\">Create an account</h2>\n      <p class=\"text-muted\" style=\"font-size:.88rem;\">Join VoteSphere and start participating</p>\n    </div>\n\n    <div class=\"card shadow-lg\" style=\"border-radius:20px;\">\n      <div class=\"card-body p-4\">\n        <form method=\"POST\">\n          {% csrf_token %}\n          {% for field in form %}\n          <div class=\"mb-3\">\n            <label class=\"form-label\">{{ field.label }}</label>\n            {{ field }}\n            {% if field.errors %}\n            {% for error in field.errors %}\n            <div class=\"d-flex align-items-center gap-1 mt-1\" style=\"font-size:.8rem;color:#dc2626;\">\n              <i class=\"bi bi-exclamation-circle-fill\"></i>{{ error }}\n            </div>\n            {% endfor %}\n            {% endif %}\n            {% if field.help_text %}\n            <div class=\"form-text\">{{ field.help_text }}</div>\n            {% endif %}\n          </div>\n          {% endfor %}\n          <button type=\"submit\" class=\"btn btn-primary w-100 py-2 mt-1\" style=\"font-size:.95rem;\">\n            <i class=\"bi bi-person-check me-2\"></i>Create Account\n          </button>\n        </form>\n      </div>\n      <div class=\"card-footer text-center\" style=\"font-size:.875rem;\">\n        Already have an account? <a href=\"{% url 'login' %}\" style=\"color:#2563eb;font-weight:700;text-decoration:none;\">Sign in</a>\n      </div>\n    </div>\n\n  </div>\n</div>\n{% endblock %}\n"
with open(os.path.join(base, "register.html"), "w", encoding="utf-8") as fh: fh.write(register_html)

vote_html = "{% extends \"poll_portal/base.html\" %}\n{% block title %}Vote{% endblock %}\n{% block main %}\n<div class=\"row justify-content-center\" style=\"margin-top:1rem;margin-bottom:3rem;\">\n  <div class=\"col-md-8 col-lg-6\">\n    <div class=\"d-flex align-items-center gap-2 mb-3\">\n      <a href=\"{% url 'home' %}\" class=\"btn btn-outline-secondary btn-sm\">\n        <i class=\"bi bi-arrow-left\"></i>\n      </a>\n      <span class=\"text-muted\" style=\"font-size:.85rem;\">Back to polls</span>\n    </div>\n    <div class=\"card shadow\" style=\"border-radius:20px;\">\n      <div class=\"card-header card-header-indigo\">\n        <div style=\"font-size:.72rem;opacity:.75;font-weight:700;text-transform:uppercase;letter-spacing:.1em;margin-bottom:.4rem;\">\n          <i class=\"bi bi-hand-index-thumb me-1\"></i>Cast Your Vote\n        </div>\n        <h5 class=\"mb-0 fw-bold\" style=\"font-size:1.05rem;line-height:1.4;\">{{ poll.question }}</h5>\n      </div>\n      <div class=\"card-body p-4\">\n        <p class=\"text-muted mb-3\" style=\"font-size:.85rem;\">Select one option below \u2014 you can only vote once.</p>\n        <form method=\"POST\" id=\"voteForm\">\n          {% csrf_token %}\n          <div class=\"d-flex flex-column gap-3 mb-4\">\n            <label class=\"vote-option\" style=\"border-radius:14px;\">\n              <input type=\"radio\" name=\"poll\" value=\"option1\">\n              <div>\n                <div style=\"font-weight:600;color:#0f172a;font-size:.92rem;\">{{ poll.option_one }}</div>\n              </div>\n            </label>\n            <label class=\"vote-option\" style=\"border-radius:14px;\">\n              <input type=\"radio\" name=\"poll\" value=\"option2\">\n              <div>\n                <div style=\"font-weight:600;color:#0f172a;font-size:.92rem;\">{{ poll.option_two }}</div>\n              </div>\n            </label>\n            <label class=\"vote-option\" style=\"border-radius:14px;\">\n              <input type=\"radio\" name=\"poll\" value=\"option3\">\n              <div>\n                <div style=\"font-weight:600;color:#0f172a;font-size:.92rem;\">{{ poll.option_three }}</div>\n              </div>\n            </label>\n          </div>\n          <div class=\"d-flex gap-2\">\n            <button type=\"submit\" class=\"btn btn-primary px-4 py-2\">\n              <i class=\"bi bi-check2-square me-2\"></i>Submit Vote\n            </button>\n            <a href=\"{% url 'home' %}\" class=\"btn btn-outline-secondary px-4 py-2\">Cancel</a>\n          </div>\n        </form>\n      </div>\n      <div class=\"card-footer d-flex align-items-center gap-2\" style=\"font-size:.8rem;color:#64748b;\">\n        <i class=\"bi bi-shield-lock-fill\" style=\"color:#2563eb;\"></i>\n        Your vote is secure and can only be cast once per poll.\n      </div>\n    </div>\n  </div>\n</div>\n{% endblock %}\n"
with open(os.path.join(base, "vote.html"), "w", encoding="utf-8") as fh: fh.write(vote_html)

results_html = "{% extends \"poll_portal/base.html\" %}\n{% block title %}Results{% endblock %}\n{% block main %}\n<div class=\"row justify-content-center\" style=\"margin-top:1rem;margin-bottom:3rem;\">\n  <div class=\"col-md-9 col-lg-7\">\n    <div class=\"d-flex align-items-center gap-2 mb-3\">\n      <a href=\"{% url 'home' %}\" class=\"btn btn-outline-secondary btn-sm\"><i class=\"bi bi-arrow-left\"></i></a>\n      <span class=\"text-muted\" style=\"font-size:.85rem;\">Back to polls</span>\n    </div>\n    <div class=\"card shadow\" style=\"border-radius:20px;\">\n      <div class=\"card-header card-header-indigo d-flex justify-content-between align-items-center\">\n        <div style=\"flex:1;\">\n          <div style=\"font-size:.7rem;opacity:.75;font-weight:700;text-transform:uppercase;letter-spacing:.1em;margin-bottom:.35rem;\">\n            <i class=\"bi bi-bar-chart-fill me-1\"></i>Poll Results\n          </div>\n          <h5 class=\"mb-0 fw-bold\" style=\"font-size:1.05rem;line-height:1.4;\">{{ poll.question }}</h5>\n        </div>\n        <div class=\"ms-3 flex-shrink-0\">\n          {% if poll.result_published %}\n          <span style=\"background:rgba(16,185,129,.25);color:#a7f3d0;font-size:.72rem;font-weight:700;padding:.35em 1em;border-radius:10px;display:inline-block;\">\n            <i class=\"bi bi-check-circle me-1\"></i>Published\n          </span>\n          {% else %}\n          <span style=\"background:rgba(245,158,11,.25);color:#fde68a;font-size:.72rem;font-weight:700;padding:.35em 1em;border-radius:10px;display:inline-block;\">\n            <i class=\"bi bi-eye-slash me-1\"></i>Admin Preview\n          </span>\n          {% endif %}\n        </div>\n      </div>\n      <div class=\"card-body p-4\">\n\n        <div class=\"mb-4\">\n          <div class=\"d-flex justify-content-between align-items-center mb-2\">\n            <div class=\"d-flex align-items-center gap-2 flex-wrap\">\n              <span style=\"width:11px;height:11px;background:#2563eb;border-radius:50%;display:inline-block;flex-shrink:0;\"></span>\n              <span style=\"font-weight:600;color:#0f172a;font-size:.9rem;\">{{ poll.option_one }}</span>\n              {% if poll.winner == poll.option_one and poll.total > 0 %}\n              <span class=\"winner-badge\"><i class=\"bi bi-trophy-fill\"></i>Winner</span>\n              {% endif %}\n              {% if user_vote == 'option1' %}\n              <span style=\"background:#dbeafe;color:#1e40af;font-size:.7rem;font-weight:600;padding:.25em .7em;border-radius:8px;\">Your vote</span>\n              {% endif %}\n            </div>\n            <span style=\"font-size:.8rem;font-weight:600;color:#64748b;\">{{ poll.option_one_count }} ({{ poll.percentage_one }}%)</span>\n          </div>\n          <div class=\"progress\">\n            <div class=\"progress-bar\" style=\"width:{{ poll.percentage_one }}%;background:linear-gradient(135deg,#2563eb,#1d4ed8);\">\n              {% if poll.percentage_one > 8 %}{{ poll.percentage_one }}%{% endif %}\n            </div>\n          </div>\n        </div>\n\n        <div class=\"mb-4\">\n          <div class=\"d-flex justify-content-between align-items-center mb-2\">\n            <div class=\"d-flex align-items-center gap-2 flex-wrap\">\n              <span style=\"width:11px;height:11px;background:#10b981;border-radius:50%;display:inline-block;flex-shrink:0;\"></span>\n              <span style=\"font-weight:600;color:#0f172a;font-size:.9rem;\">{{ poll.option_two }}</span>\n              {% if poll.winner == poll.option_two and poll.total > 0 %}\n              <span class=\"winner-badge\"><i class=\"bi bi-trophy-fill\"></i>Winner</span>\n              {% endif %}\n              {% if user_vote == 'option2' %}\n              <span style=\"background:#dbeafe;color:#1e40af;font-size:.7rem;font-weight:600;padding:.25em .7em;border-radius:8px;\">Your vote</span>\n              {% endif %}\n            </div>\n            <span style=\"font-size:.8rem;font-weight:600;color:#64748b;\">{{ poll.option_two_count }} ({{ poll.percentage_two }}%)</span>\n          </div>\n          <div class=\"progress\">\n            <div class=\"progress-bar\" style=\"width:{{ poll.percentage_two }}%;background:linear-gradient(135deg,#10b981,#059669);\">\n              {% if poll.percentage_two > 8 %}{{ poll.percentage_two }}%{% endif %}\n            </div>\n          </div>\n        </div>\n\n        <div class=\"mb-4\">\n          <div class=\"d-flex justify-content-between align-items-center mb-2\">\n            <div class=\"d-flex align-items-center gap-2 flex-wrap\">\n              <span style=\"width:11px;height:11px;background:#f59e0b;border-radius:50%;display:inline-block;flex-shrink:0;\"></span>\n              <span style=\"font-weight:600;color:#0f172a;font-size:.9rem;\">{{ poll.option_three }}</span>\n              {% if poll.winner == poll.option_three and poll.total > 0 %}\n              <span class=\"winner-badge\"><i class=\"bi bi-trophy-fill\"></i>Winner</span>\n              {% endif %}\n              {% if user_vote == 'option3' %}\n              <span style=\"background:#dbeafe;color:#1e40af;font-size:.7rem;font-weight:600;padding:.25em .7em;border-radius:8px;\">Your vote</span>\n              {% endif %}\n            </div>\n            <span style=\"font-size:.8rem;font-weight:600;color:#64748b;\">{{ poll.option_three_count }} ({{ poll.percentage_three }}%)</span>\n          </div>\n          <div class=\"progress\">\n            <div class=\"progress-bar\" style=\"width:{{ poll.percentage_three }}%;background:linear-gradient(135deg,#f59e0b,#d97706);\">\n              {% if poll.percentage_three > 8 %}{{ poll.percentage_three }}%{% endif %}\n            </div>\n          </div>\n        </div>\n\n        <div class=\"divider\"></div>\n        <div class=\"d-flex justify-content-between align-items-center p-3 rounded-3\" style=\"background:#eff6ff;\">\n          <div style=\"font-weight:700;color:#0f172a;\">\n            <i class=\"bi bi-people-fill me-2\" style=\"color:#2563eb;\"></i>{{ poll.total }} total vote{{ poll.total|pluralize }}\n          </div>\n          {% if poll.total > 0 %}\n          <div style=\"font-size:.82rem;color:#64748b;\">Leading: <strong style=\"color:#2563eb;\">{{ poll.winner }}</strong></div>\n          {% endif %}\n        </div>\n      </div>\n      <div class=\"card-footer d-flex gap-2 flex-wrap\">\n        <a href=\"{% url 'home' %}\" class=\"btn btn-outline-secondary btn-sm\">\n          <i class=\"bi bi-arrow-left me-1\"></i>Back\n        </a>\n        {% if user.is_staff %}\n        <a href=\"{% url 'voters_list' poll.id %}\" class=\"btn btn-outline-primary btn-sm\">\n          <i class=\"bi bi-people me-1\"></i>Voters\n        </a>\n        <a href=\"{% url 'declare_result' poll.id %}\" class=\"btn btn-sm {% if poll.result_published %}btn-outline-warning{% else %}btn-success{% endif %}\">\n          {% if poll.result_published %}\n          <i class=\"bi bi-eye-slash me-1\"></i>Unpublish\n          {% else %}\n          <i class=\"bi bi-send me-1\"></i>Publish Results\n          {% endif %}\n        </a>\n        {% endif %}\n      </div>\n    </div>\n  </div>\n</div>\n{% endblock %}\n"
with open(os.path.join(base, "results.html"), "w", encoding="utf-8") as fh: fh.write(results_html)

admin_dashboard_html = "{% extends \"poll_portal/base.html\" %}\n{% block title %}Admin Dashboard{% endblock %}\n{% block main %}\n\n<div class=\"d-flex justify-content-between align-items-center mb-4\">\n  <div>\n    <h3 style=\"font-weight:800;color:#0f172a;margin-bottom:.2rem;font-size:1.6rem;\">Dashboard</h3>\n    <div class=\"text-muted\" style=\"font-size:.85rem;\">Manage polls, publish results, and monitor voter activity</div>\n  </div>\n  <a href=\"{% url 'create' %}\" class=\"btn btn-primary px-4 py-2\">\n    <i class=\"bi bi-plus-circle me-2\"></i>New Poll\n  </a>\n</div>\n\n<div class=\"row g-3 mb-4\">\n  <div class=\"col-sm-4\">\n    <div class=\"stat-card\">\n      <div class=\"stat-icon\"><i class=\"bi bi-list-task\"></i></div>\n      <div class=\"stat-number\" style=\"color:#2563eb;\">{{ total_polls }}</div>\n      <div class=\"stat-label\">Total Polls</div>\n    </div>\n  </div>\n  <div class=\"col-sm-4\">\n    <div class=\"stat-card\">\n      <div class=\"stat-icon\"><i class=\"bi bi-play-circle\"></i></div>\n      <div class=\"stat-number\" style=\"color:#10b981;\">{{ active_polls }}</div>\n      <div class=\"stat-label\">Active Polls</div>\n    </div>\n  </div>\n  <div class=\"col-sm-4\">\n    <div class=\"stat-card\">\n      <div class=\"stat-icon\"><i class=\"bi bi-people\"></i></div>\n      <div class=\"stat-number\" style=\"color:#f59e0b;\">{{ total_votes }}</div>\n      <div class=\"stat-label\">Votes Cast</div>\n    </div>\n  </div>\n</div>\n\n<div class=\"card\">\n  <div class=\"card-header card-header-dark d-flex justify-content-between align-items-center\">\n    <div style=\"font-weight:700;font-size:.95rem;\">\n      <i class=\"bi bi-table me-2\"></i>All Polls\n    </div>\n    <span style=\"background:rgba(255,255,255,.15);color:rgba(255,255,255,.8);font-size:.72rem;font-weight:600;padding:.3em .9em;border-radius:8px;\">{{ total_polls }} total</span>\n  </div>\n  <div class=\"card-body p-0\">\n    {% if polls %}\n    <div class=\"table-responsive\">\n      <table class=\"table table-hover align-middle mb-0\">\n        <thead>\n          <tr>\n            <th style=\"padding:.9rem 1.2rem;\">Question</th>\n            <th>Votes</th>\n            <th>Status</th>\n            <th>Results</th>\n            <th>Date</th>\n            <th style=\"padding:.9rem 1.2rem;\">Actions</th>\n          </tr>\n        </thead>\n        <tbody>\n          {% for poll in polls %}\n          <tr>\n            <td style=\"padding:.85rem 1.2rem;\">\n              <span style=\"font-weight:600;color:#0f172a;\">{{ poll.question|truncatechars:52 }}</span>\n            </td>\n            <td>\n              <span style=\"display:inline-flex;align-items:center;gap:4px;background:#dbeafe;color:#2563eb;border-radius:8px;padding:.25rem .65rem;font-weight:700;font-size:.8rem;\">\n                <i class=\"bi bi-people-fill\"></i>{{ poll.total }}\n              </span>\n            </td>\n            <td>\n              {% if poll.is_active %}\n              <span style=\"background:#d1fae5;color:#065f46;font-size:.75rem;font-weight:600;padding:.3em .75em;border-radius:8px;display:inline-block;\">\n                <i class=\"bi bi-circle-fill me-1\" style=\"font-size:.4rem;\"></i>Active\n              </span>\n              {% else %}\n              <span style=\"background:#fee2e2;color:#991b1b;font-size:.75rem;font-weight:600;padding:.3em .75em;border-radius:8px;display:inline-block;\">\n                Closed\n              </span>\n              {% endif %}\n            </td>\n            <td>\n              {% if poll.result_published %}\n              <span style=\"background:#dbeafe;color:#1e40af;font-size:.75rem;font-weight:600;padding:.3em .75em;border-radius:8px;display:inline-block;\">\n                <i class=\"bi bi-eye me-1\"></i>Live\n              </span>\n              {% else %}\n              <span style=\"background:#f1f5f9;color:#64748b;font-size:.75rem;font-weight:600;padding:.3em .75em;border-radius:8px;display:inline-block;\">\n                Hidden\n              </span>\n              {% endif %}\n            </td>\n            <td style=\"font-size:.8rem;color:#94a3b8;\">{{ poll.pub_date|date:\"M d, Y\" }}</td>\n            <td style=\"padding:.85rem 1.2rem;\">\n              <div class=\"d-flex gap-1 flex-wrap\">\n                <a href=\"{% url 'results' poll.id %}\" class=\"btn btn-outline-primary btn-sm\" title=\"Results\"><i class=\"bi bi-bar-chart\"></i></a>\n                <a href=\"{% url 'voters_list' poll.id %}\" class=\"btn btn-outline-secondary btn-sm\" title=\"Voters\"><i class=\"bi bi-people\"></i></a>\n                <a href=\"{% url 'declare_result' poll.id %}\" class=\"btn btn-sm {% if poll.result_published %}btn-outline-warning{% else %}btn-outline-success{% endif %}\" title=\"Toggle Results\">\n                  {% if poll.result_published %}<i class=\"bi bi-eye-slash\"></i>{% else %}<i class=\"bi bi-eye\"></i>{% endif %}\n                </a>\n                <a href=\"{% url 'toggle_active' poll.id %}\" class=\"btn btn-sm {% if poll.is_active %}btn-outline-danger{% else %}btn-outline-success{% endif %}\" title=\"Toggle Active\">\n                  {% if poll.is_active %}<i class=\"bi bi-stop-circle\"></i>{% else %}<i class=\"bi bi-play-circle\"></i>{% endif %}\n                </a>\n                <a href=\"{% url 'delete' poll.id %}\" class=\"btn btn-danger btn-sm\" title=\"Delete\"><i class=\"bi bi-trash3\"></i></a>\n              </div>\n            </td>\n          </tr>\n          {% endfor %}\n        </tbody>\n      </table>\n    </div>\n    {% else %}\n    <div class=\"p-5 text-center\">\n      <div style=\"width:64px;height:64px;background:#dbeafe;border-radius:50%;display:flex;align-items:center;justify-content:center;margin:0 auto 1rem;\">\n        <i class=\"bi bi-inbox\" style=\"font-size:1.8rem;color:#2563eb;\"></i>\n      </div>\n      <p class=\"text-muted mb-3\">No polls created yet.</p>\n      <a href=\"{% url 'create' %}\" class=\"btn btn-primary px-4\"><i class=\"bi bi-plus-circle me-2\"></i>Create First Poll</a>\n    </div>\n    {% endif %}\n  </div>\n</div>\n\n<div class=\"mt-3 d-flex flex-wrap gap-3\" style=\"font-size:.76rem;color:#94a3b8;\">\n  <span><i class=\"bi bi-bar-chart text-primary me-1\"></i>Results</span>\n  <span><i class=\"bi bi-people text-secondary me-1\"></i>Voters</span>\n  <span><i class=\"bi bi-eye text-success me-1\"></i>Publish/Unpublish</span>\n  <span><i class=\"bi bi-stop-circle text-danger me-1\"></i>Open/Close</span>\n  <span><i class=\"bi bi-trash3 text-danger me-1\"></i>Delete</span>\n</div>\n{% endblock %}\n"
with open(os.path.join(base, "admin_dashboard.html"), "w", encoding="utf-8") as fh: fh.write(admin_dashboard_html)

voters_html = "{% extends \"poll_portal/base.html\" %}\n{% block title %}Voters List{% endblock %}\n{% block main %}\n<div class=\"row justify-content-center\" style=\"margin-top:1rem;margin-bottom:3rem;\">\n  <div class=\"col-lg-10\">\n    <div class=\"d-flex align-items-center gap-3 mb-3\">\n      <a href=\"{% url 'admin_dashboard' %}\" class=\"btn btn-outline-secondary btn-sm\"><i class=\"bi bi-arrow-left\"></i></a>\n      <div>\n        <div style=\"font-weight:800;color:#0f172a;font-size:1.1rem;\">Voters List</div>\n        <div class=\"text-muted\" style=\"font-size:.82rem;\">{{ poll.question|truncatechars:70 }}</div>\n      </div>\n    </div>\n    <div class=\"card shadow\" style=\"border-radius:20px;\">\n      <div class=\"card-header card-header-dark d-flex justify-content-between align-items-center\">\n        <div style=\"font-weight:700;font-size:.95rem;\">\n          <i class=\"bi bi-people-fill me-2\"></i>Who Voted\n        </div>\n        <span style=\"background:rgba(255,255,255,.18);color:rgba(255,255,255,.85);font-size:.75rem;font-weight:700;padding:.35em .9em;border-radius:8px;\">\n          {{ votes.count }} voter{{ votes.count|pluralize }}\n        </span>\n      </div>\n      <div class=\"card-body p-0\">\n        {% if votes %}\n        <div class=\"table-responsive\">\n          <table class=\"table table-hover mb-0\">\n            <thead>\n              <tr>\n                <th style=\"padding:.85rem 1.2rem;\">#</th>\n                <th>Voter</th>\n                <th>Voted For</th>\n                <th>Date &amp; Time</th>\n              </tr>\n            </thead>\n            <tbody>\n              {% for v in votes %}\n              <tr>\n                <td style=\"padding:.85rem 1.2rem;color:#94a3b8;font-weight:700;font-size:.82rem;\">{{ forloop.counter }}</td>\n                <td>\n                  <div class=\"d-flex align-items-center gap-2\">\n                    <div style=\"width:32px;height:32px;background:linear-gradient(135deg,#2563eb,#1d4ed8);border-radius:50%;display:flex;align-items:center;justify-content:center;color:#fff;font-weight:700;font-size:.8rem;flex-shrink:0;\">\n                      {{ v.user.username|first|upper }}\n                    </div>\n                    <div>\n                      <div style=\"font-weight:600;color:#0f172a;font-size:.875rem;\">{{ v.user.username }}</div>\n                      {% if v.user.is_staff %}<span style=\"background:#fef3c7;color:#92400e;font-size:.68rem;font-weight:700;padding:.2em .6em;border-radius:6px;\">Admin</span>{% endif %}\n                    </div>\n                  </div>\n                </td>\n                <td>\n                  {% if v.choice == 'option1' %}\n                  <span style=\"background:#dbeafe;color:#1d4ed8;font-size:.78rem;font-weight:600;padding:.3em .75em;border-radius:8px;display:inline-block;\">{{ poll.option_one }}</span>\n                  {% elif v.choice == 'option2' %}\n                  <span style=\"background:#d1fae5;color:#065f46;font-size:.78rem;font-weight:600;padding:.3em .75em;border-radius:8px;display:inline-block;\">{{ poll.option_two }}</span>\n                  {% else %}\n                  <span style=\"background:#fef3c7;color:#92400e;font-size:.78rem;font-weight:600;padding:.3em .75em;border-radius:8px;display:inline-block;\">{{ poll.option_three }}</span>\n                  {% endif %}\n                </td>\n                <td style=\"font-size:.8rem;color:#94a3b8;\">{{ v.voted_on|date:\"M d, Y\" }} at {{ v.voted_on|date:\"H:i\" }}</td>\n              </tr>\n              {% endfor %}\n            </tbody>\n          </table>\n        </div>\n        {% else %}\n        <div class=\"p-5 text-center\">\n          <div style=\"width:64px;height:64px;background:#dbeafe;border-radius:50%;display:flex;align-items:center;justify-content:center;margin:0 auto 1rem;\">\n            <i class=\"bi bi-inbox\" style=\"font-size:1.8rem;color:#2563eb;\"></i>\n          </div>\n          <p class=\"text-muted mb-0\">No votes cast yet for this poll.</p>\n        </div>\n        {% endif %}\n      </div>\n      <div class=\"card-footer d-flex gap-2\">\n        <a href=\"{% url 'admin_dashboard' %}\" class=\"btn btn-outline-secondary btn-sm\">\n          <i class=\"bi bi-speedometer2 me-1\"></i>Dashboard\n        </a>\n        <a href=\"{% url 'results' poll.id %}\" class=\"btn btn-outline-primary btn-sm\">\n          <i class=\"bi bi-bar-chart me-1\"></i>View Results\n        </a>\n      </div>\n    </div>\n  </div>\n</div>\n{% endblock %}\n"
with open(os.path.join(base, "voters.html"), "w", encoding="utf-8") as fh: fh.write(voters_html)

create_html = "{% extends \"poll_portal/base.html\" %}\n{% block title %}Create Poll{% endblock %}\n{% block main %}\n<div class=\"row justify-content-center\" style=\"margin-top:1rem;margin-bottom:3rem;\">\n  <div class=\"col-md-9 col-lg-7\">\n    <div class=\"d-flex align-items-center gap-3 mb-3\">\n      <a href=\"{% url 'admin_dashboard' %}\" class=\"btn btn-outline-secondary btn-sm\"><i class=\"bi bi-arrow-left\"></i></a>\n      <div>\n        <div style=\"font-weight:800;color:#0f172a;font-size:1.1rem;\">Create New Poll</div>\n        <div class=\"text-muted\" style=\"font-size:.82rem;\">Fill in the details below and publish instantly</div>\n      </div>\n    </div>\n    <div class=\"card shadow\" style=\"border-radius:20px;\">\n      <div class=\"card-header card-header-indigo\">\n        <h5 class=\"mb-0\"><i class=\"bi bi-plus-circle me-2\"></i>Poll Details</h5>\n      </div>\n      <div class=\"card-body p-4\">\n        <form method=\"POST\">\n          {% csrf_token %}\n          <div class=\"mb-4\">\n            <label class=\"form-label\">Poll Question</label>\n            {{ form.question }}\n            {% if form.question.errors %}<div style=\"color:#dc2626;font-size:.8rem;margin-top:.3rem;\">{{ form.question.errors }}</div>{% endif %}\n          </div>\n          <div class=\"divider\"></div>\n          <div style=\"font-weight:700;font-size:.78rem;color:#2563eb;text-transform:uppercase;letter-spacing:.08em;margin-bottom:.75rem;\">\n            <i class=\"bi bi-list-ul me-1\"></i>Answer Options\n          </div>\n          <div class=\"row g-3 mb-4\">\n            <div class=\"col-md-4\">\n              <div class=\"p-3 rounded-3\" style=\"background:#eff6ff;border:1.5px solid #dbeafe;\">\n                <label class=\"form-label\" style=\"color:#2563eb;\">Option A</label>\n                {{ form.option_one }}\n                {% if form.option_one.errors %}<div style=\"color:#dc2626;font-size:.8rem;margin-top:.3rem;\">{{ form.option_one.errors }}</div>{% endif %}\n              </div>\n            </div>\n            <div class=\"col-md-4\">\n              <div class=\"p-3 rounded-3\" style=\"background:#eff6ff;border:1.5px solid #dbeafe;\">\n                <label class=\"form-label\" style=\"color:#1d4ed8;\">Option B</label>\n                {{ form.option_two }}\n                {% if form.option_two.errors %}<div style=\"color:#dc2626;font-size:.8rem;margin-top:.3rem;\">{{ form.option_two.errors }}</div>{% endif %}\n              </div>\n            </div>\n            <div class=\"col-md-4\">\n              <div class=\"p-3 rounded-3\" style=\"background:#eff6ff;border:1.5px solid #dbeafe;\">\n                <label class=\"form-label\" style=\"color:#3b82f6;\">Option C</label>\n                {{ form.option_three }}\n                {% if form.option_three.errors %}<div style=\"color:#dc2626;font-size:.8rem;margin-top:.3rem;\">{{ form.option_three.errors }}</div>{% endif %}\n              </div>\n            </div>\n          </div>\n          <div class=\"d-flex gap-2\">\n            <button type=\"submit\" class=\"btn btn-primary px-4 py-2\">\n              <i class=\"bi bi-send me-2\"></i>Publish Poll\n            </button>\n            <a href=\"{% url 'admin_dashboard' %}\" class=\"btn btn-outline-secondary px-4\">Cancel</a>\n          </div>\n        </form>\n      </div>\n    </div>\n  </div>\n</div>\n{% endblock %}\n"
with open(os.path.join(base, "create.html"), "w", encoding="utf-8") as fh: fh.write(create_html)

delete_html = "{% extends \"poll_portal/base.html\" %}\n{% block title %}Delete Poll{% endblock %}\n{% block main %}\n<div class=\"row justify-content-center\" style=\"margin-top:2rem;margin-bottom:3rem;\">\n  <div class=\"col-md-6 col-lg-5\">\n    <div class=\"card shadow-lg\" style=\"border-radius:20px;border:2px solid #fee2e2;\">\n      <div class=\"card-header\" style=\"background:linear-gradient(135deg,#ef4444,#b91c1c);border-radius:18px 18px 0 0!important;\">\n        <h5 class=\"mb-0 text-white\" style=\"font-size:.95rem;\">\n          <i class=\"bi bi-exclamation-triangle-fill me-2\"></i>Confirm Deletion\n        </h5>\n      </div>\n      <div class=\"card-body p-4 text-center\">\n        <div style=\"width:72px;height:72px;background:#fee2e2;border-radius:50%;display:flex;align-items:center;justify-content:center;margin:0 auto 1.5rem;\">\n          <i class=\"bi bi-trash3-fill\" style=\"font-size:2rem;color:#dc2626;\"></i>\n        </div>\n        <p class=\"text-muted mb-2\" style=\"font-size:.9rem;\">You are about to permanently delete:</p>\n        <div style=\"font-weight:700;color:#0f172a;font-size:1rem;margin-bottom:1rem;padding:0 1rem;\">\n          &#34;{{ poll.question }}&#34;\n        </div>\n        <div class=\"d-inline-flex align-items-center gap-2 px-3 py-2 rounded-3 mb-4\" style=\"background:#fee2e2;color:#991b1b;font-size:.82rem;font-weight:600;\">\n          <i class=\"bi bi-info-circle-fill\"></i>\n          {{ poll.total }} vote{{ poll.total|pluralize }} will also be deleted. This cannot be undone.\n        </div>\n        <form method=\"POST\">\n          {% csrf_token %}\n          <div class=\"d-flex justify-content-center gap-3\">\n            <button type=\"submit\" class=\"btn btn-danger px-4 py-2\">\n              <i class=\"bi bi-trash3 me-2\"></i>Yes, Delete\n            </button>\n            <a href=\"{% url 'admin_dashboard' %}\" class=\"btn btn-outline-secondary px-4 py-2\">Cancel</a>\n          </div>\n        </form>\n      </div>\n    </div>\n  </div>\n</div>\n{% endblock %}\n"
with open(os.path.join(base, "delete.html"), "w", encoding="utf-8") as fh: fh.write(delete_html)

